/* 772 — map W1-mask / sentinel-collision fix.
 *
 * Falsifier: fill a map to 100% OCCUPIED (hard_max == initial cap, no removes,
 * so map_grow is blocked and zero tombstones exist).  Then probe a missing key.
 * BROKEN: map_probe_internal returns MAP_IDX_FULL (0xFFFF...) which has bit 63
 * set, aliasing MAP_FOUND_BIT.  get/contains/remove misclassify as found.
 *   - contains(missing) -> 1u8  (false positive, verifiable without crash)
 *   - get(missing) -> deref base+17GB -> segfault
 *   - remove(missing) -> deref + tombstone bogus slot -> segfault
 * FIXED: MAP_IDX_FULL retired; full-table probe returns MAP_FULL_BIT (bit 62)
 * which is disjoint from MAP_FOUND_BIT (bit 63).  All three return none/0/none.
 *
 * Also asserts get/contains/remove on an ABSENT key in a NON-full table
 * (early-exit path: first empty slot terminates probe with neither flag bit set).
 *
 * Expected exit: 99. */
module corpus_772

extern @abi(c-msvc-x64) fn arena_new(bytes: u64) -> u64 from "arena.iii"
extern @abi(c-msvc-x64) fn arena_drop(id: u64) -> i32 from "arena.iii"
extern @abi(c-msvc-x64) fn map_u32u32_new(arena: u64, hard: u64) -> u64 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_put(id: u64, k: u32, v: u32) -> i32 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_get(id: u64, k: u32) -> u64 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_contains(id: u64, k: u32) -> u8 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_remove(id: u64, k: u32) -> u64 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_len(id: u64) -> u64 from "map.iii"
extern @abi(c-msvc-x64) fn map_u32u32_drop(id: u64) -> i32 from "map.iii"

/* arena large enough for keys+vals+states at hard_max=8, initial_cap=8 */
const ARENA_BYTES : u64 = 4096u64
const HARD_MAX    : u64 = 8u64

fn main() -> u64 {
    /* --- Part 1: NON-full table --- absent key must never be found --- */
    let a1 : u64 = arena_new(ARENA_BYTES)
    if a1 == 0u64 { return 1u64 }
    let m1 : u64 = map_u32u32_new(a1, HARD_MAX)
    if m1 == 0u64 { return 2u64 }
    /* Insert 3 of 8 slots (well under load threshold). */
    if map_u32u32_put(m1, 10u32, 100u32) != 0i32 { return 3u64 }
    if map_u32u32_put(m1, 20u32, 200u32) != 0i32 { return 4u64 }
    if map_u32u32_put(m1, 30u32, 300u32) != 0i32 { return 5u64 }
    /* Missing key 999 must return none / 0 / none. */
    if map_u32u32_contains(m1, 999u32) != 0u8 { return 10u64 }   /* false-positive check */
    let g1 : u64 = map_u32u32_get(m1, 999u32)
    if g1 != 0u64 { return 11u64 }                               /* none == 0 */
    let rm1 : u64 = map_u32u32_remove(m1, 999u32)
    if rm1 != 0u64 { return 12u64 }                              /* none == 0 */
    if map_u32u32_len(m1) != 3u64 { return 13u64 }              /* remove did nothing */
    /* Present key still found. */
    let gp : u64 = map_u32u32_get(m1, 20u32)
    if (gp & 1u64) != 1u64 { return 14u64 }                     /* some bit set */
    if ((gp >> 1u64) & 0xFFFFFFFFu64) != 200u64 { return 15u64 }
    map_u32u32_drop(m1)
    arena_drop(a1)

    /* --- Part 2: 100%-OCCUPIED table (hard_max == cap, no tombstones) --- */
    /* hard_max=8: map_u32u32_new clamps to init_cap=8 (is a power-of-two).   */
    /* map_grow blocked: new_cap = 8*2 = 16 > hard=8 -> clamped to 8 = cap -> E_FULL. */
    /* 75%-threshold triggers at len=6 (4*(6+1)=28 > 3*8=24). map_grow fires  */
    /* but returns E_FULL (not OOM). put continues and probes for the slot.     */
    /* We insert all 8 keys: indices 0..7 (no tombstones, 100% OCCUPIED).       */
    let a2 : u64 = arena_new(ARENA_BYTES)
    if a2 == 0u64 { return 20u64 }
    /* hard_max=8 but we need cap=8 and no grow possible. */
    let m2 : u64 = map_u32u32_new(a2, 8u64)
    if m2 == 0u64 { return 21u64 }
    let mut i : u32 = 0u32
    while i < 8u32 {
        let rc : i32 = map_u32u32_put(m2, i, i)
        /* rc may be 0 (ok) or -2 (MAP_E_FULL from grow, but put still succeeds
         * by probing) or 0 after the full-sentinel fix.  We only care that the
         * value is eventually retrievable, not about the grow error code. */
        if rc != 0i32 {
            /* If put fails entirely (MAP_E_FULL from the probe), the table ran
             * out of physical slots.  That means cap < 8 which shouldn't happen
             * with hard=8 and power-of-two init.  Return an error to diagnose. */
            return 30u64
        }
        i = i + 1u32
    }
    if map_u32u32_len(m2) != 8u64 { return 31u64 }
    /* Key 999 is absent.  Table is 100% OCCUPIED, zero tombstones.
     * BROKEN: probe returns all-ones sentinel -> bit63 alias -> false found.
     * FIXED:  probe returns MAP_FULL_BIT (bit62) -> bit63 clear -> none/0/none. */
    if map_u32u32_contains(m2, 999u32) != 0u8 { return 40u64 }  /* [FALSIFIER] */
    let g2 : u64 = map_u32u32_get(m2, 999u32)
    if g2 != 0u64 { return 41u64 }                              /* [FALSIFIER: OOB on broken] */
    let rm2 : u64 = map_u32u32_remove(m2, 999u32)
    if rm2 != 0u64 { return 42u64 }                             /* [FALSIFIER: OOB on broken] */
    if map_u32u32_len(m2) != 8u64 { return 43u64 }             /* len must not change */
    /* Present keys still retrievable in the full table. */
    let mut j : u32 = 0u32
    while j < 8u32 {
        let gj : u64 = map_u32u32_get(m2, j)
        if (gj & 1u64) != 1u64 { return 50u64 }
        if ((gj >> 1u64) & 0xFFFFFFFFu64) != (j as u64) { return 51u64 }
        j = j + 1u32
    }
    map_u32u32_drop(m2)
    arena_drop(a2)
    return 99u64
}
